import React from 'react';

function Achievements({ data }) {
  if (!data) return null;

  return (
    <section id="achievements" className="py-12 md:py-16 bg-[#f6f1e7]">
      <div className="max-w-7xl mx-auto px-4">
        <div className="mb-8 md:mb-10">
          <p className="text-[10px] uppercase tracking-[0.4em] text-[#7b7367] font-semibold mb-3">
            Achievements
          </p>
          <h2
            className="text-3xl md:text-5xl text-[#1d1c19]"
            style={{ fontFamily: '"Playfair Display", "Times New Roman", serif', fontWeight: 700 }}
          >
            Milestones
          </h2>
        </div>

        <div className="grid sm:grid-cols-2 xl:grid-cols-3 gap-4 md:gap-5">
          {data.map((achievement) => (
            <article key={achievement.id} className="rounded-3xl border border-[#ddd3c5] bg-white p-6 shadow-[0_14px_35px_rgba(17,17,17,0.06)]">
              <p className="text-[10px] uppercase tracking-[0.28em] text-[#7b7367] mb-3">{achievement.year}</p>
              <h3 className="text-xl md:text-2xl font-black text-[#1f1d1a] leading-tight">
                {achievement.title}
              </h3>
            </article>
          ))}
        </div>
      </div>
    </section>
  );
}

export default Achievements;
